// ============================================================================
// HELPERS
// ============================================================================

function generateSlug(title: string): string {
	return title
		.toLowerCase()
		.replace(/[^a-z0-9\s-]/g, '')
		.replace(/\s+/g, '-')
		.replace(/-+/g, '-')
		.replace(/^-|-$/g, '')
		.substring(0, 50);
}

function sleep(ms: number): Promise<void> {
	return new Promise((resolve) => setTimeout(resolve, ms));
}

function inferDeliveryMethod(
	targetType: string | null | undefined,
	geoScope?: GeoScope
): string {
	// Federal / congressional → CWC
	if (targetType === 'government') {
		if (!geoScope || geoScope.type === 'nationwide' || geoScope.type === 'international') {
			return 'cwc';
		}
		// Subnational government → email (city/state officials)
		if (geoScope.type === 'subnational' && geoScope.locality) {
			return 'email';
		}
		return 'cwc';
	}
	// Corporate / institutional → email
	return 'email';
}

function buildRecipientConfig(
	decisionMakers: DecisionMaker[],
	deliveryMethod: string
): Record<string, unknown> {
	if (deliveryMethod === 'cwc') {
		return {
			reach: 'district-based',
			cwcRouting: true,
			chambers: ['house', 'senate']
		};
	}

	return {
		reach: 'location-specific',
		decisionMakers: decisionMakers.map((dm) => ({
			name: dm.name,
			shortName: dm.name.split(' ').pop(),
			role: dm.title,
			organization: dm.organization,
			email: dm.email
		})),
		emails: decisionMakers.map((dm) => dm.email).filter(Boolean)
	};
}

